288	export class CredentialService {
289	  private clientCache: Map<string, CredentialClient> = new Map();
290	
291	  async getCredentials(organizationId: string): Promise<Record<string, CredentialClient>> {
292	    const creds = await db.query.credentials.findMany({
293	      where: eq(credentials.organizationId, organizationId),
294	    });
295	
296	    const credentialClients: Record<string, CredentialClient> = {};
297	
298	    for (const cred of creds) {
299	      const cacheKey = `${organizationId}:${cred.id}`;
300	      
301	      // Check cache first
302	      if (this.clientCache.has(cacheKey)) {
303	        credentialClients[cred.name] = this.clientCache.get(cacheKey)!;
304	        continue;
305	      }
306	
307	      // Decrypt and create client
308	      try {
309	        const config = decryptObject<CredentialConfig>(cred.config as string);
310	        const client = this.createClient(cred.type, config);
311	        
312	        this.clientCache.set(cacheKey, client);
313	        credentialClients[cred.name] = client;
314	      } catch (error) {
315	        log.error({ err: error, credential: cred.name }, 'Failed to initialize credential');
316	      }
317	    }
318	
319	    return credentialClients;
320	  }
321	
322	  private createClient(type: string, config: CredentialConfig): CredentialClient {
323	    switch (type) {
324	      case 'postgres':
325	        return new PostgresCredential(config as PostgresConfig);
326	      case 'mysql':
327	        return new MySQLCredential(config as MySQLConfig);
328	      case 'mongodb':
329	        return new MongoDBCredential(config as MongoDBConfig);
330	      case 'redis':
331	        return new RedisCredential(config as RedisConfig);
332	      case 'openai':
333	        return new OpenAICredential(config as OpenAIConfig);
334	      case 'anthropic':
335	        return new AnthropicCredential(config as AnthropicConfig);
336	      case 'google':
337	        return new GoogleAICredential(config as GoogleAIConfig);
338	      case 'ollama':
339	        return new OllamaCredential(config as OllamaConfig);
340	      default:
341	        throw new Error(`Unknown credential type: ${type}`);
342	    }
343	  }
344	
345	  async disconnectAll() {
346	    for (const client of this.clientCache.values()) {
347	      try {
348	        await client.disconnect();
349	      } catch (error) {
350	        log.error({ err: error }, 'Error disconnecting client');
351	      }
352	    }
353	    this.clientCache.clear();
354	  }
355	}
