1	import crypto from 'crypto';
2	import { env } from '@/lib/env';
3	
4	// Encryption key from validated environment (must be 32 bytes for AES-256)
5	const getEncryptionKey = (): Buffer => {
6	  const key = env.ENCRYPTION_KEY;
7	  
8	  // If the key is not exactly 32 bytes, hash it to get 32 bytes
9	  if (key.length !== 64) { // 32 bytes = 64 hex characters
10	    return crypto.createHash('sha256').update(key).digest();
11	  }
12	  
13	  return Buffer.from(key, 'hex');
14	};
15	
16	const ALGORITHM = 'aes-256-gcm';
17	const IV_LENGTH = 16; // For GCM
18	const AUTH_TAG_LENGTH = 16;
19	
20	export function encrypt(text: string): string {
21	  try {
22	    const key = getEncryptionKey();
23	    const iv = crypto.randomBytes(IV_LENGTH);
24	    
25	    const cipher = crypto.createCipheriv(ALGORITHM, key, iv);
26	    
27	    let encrypted = cipher.update(text, 'utf8', 'hex');
28	    encrypted += cipher.final('hex');
29	    
30	    const authTag = cipher.getAuthTag();
31	    
32	    // Return: iv:authTag:encryptedData (all in hex)
33	    return `${iv.toString('hex')}:${authTag.toString('hex')}:${encrypted}`;
34	  } catch (error) {
35	    console.error('Encryption error:', error);
36	    throw new Error('Failed to encrypt data');
37	  }
38	}
39	
40	export function decrypt(encryptedText: string): string {
41	  try {
42	    const key = getEncryptionKey();
43	    
44	    const parts = encryptedText.split(':');
45	    if (parts.length !== 3) {
46	      throw new Error('Invalid encrypted data format');
47	    }
48	    
49	    const [ivHex, authTagHex, encrypted] = parts;
50	    const iv = Buffer.from(ivHex, 'hex');
51	    const authTag = Buffer.from(authTagHex, 'hex');
52	    
53	    const decipher = crypto.createDecipheriv(ALGORITHM, key, iv);
54	    decipher.setAuthTag(authTag);
55	    
56	    let decrypted = decipher.update(encrypted, 'hex', 'utf8');
57	    decrypted += decipher.final('utf8');
58	    
59	    return decrypted;
60	  } catch (error) {
61	    console.error('Decryption error:', error);
62	    throw new Error('Failed to decrypt data');
63	  }
64	}
65	
66	// Helper functions for encrypting/decrypting objects
67	export function encryptObject(obj: unknown): string {
68	  return encrypt(JSON.stringify(obj));
69	}
70	
71	export function decryptObject<T>(encryptedText: string): T {
72	  return JSON.parse(decrypt(encryptedText)) as T;
73	}
